options.getOption:
const allSeries = context.panel.data.series;
if (!allSeries || allSeries.length < 1) return { series: [] };

const fld = (s, name) => {
  const f = s.fields.find(x => x.name === name);
  if (!f) return [];
  const v = f.values;
  return (v && v.buffer) ? v.buffer : (v || []);
};

const links = [];
const nodeSet = new Set();

for (const s of allSeries) {
  if (!s || !s.fields || s.fields.length < 3) continue;
  const sources = fld(s, 'source');
  const targets = fld(s, 'target');
  const values  = fld(s, 'value');
  for (let i = 0; i < sources.length; i++) {
    const v = parseFloat(values[i]) || 0;
    const src = String(sources[i]);
    const tgt = String(targets[i]);
    if (v > 0 && src !== tgt) {
      links.push({ source: src, target: tgt, value: v });
      nodeSet.add(src);
      nodeSet.add(tgt);
    }
  }
}
if (!links.length) return { series: [] };

const phaseColors = { 'design':'#FADE2A','build':'#73BF69','test':'#73BF69','review':'#5794F2','rework':'#FF780A','admin':'#A9A9A9' };
const wtColors = { 'feature':'#FF780A','bug':'#FADE2A','research':'#B877D9','docs':'#5794F2','test':'#73BF69','infra':'#F2495C','refactor':'#64A0C8','admin':'#A9A9A9' };
const allColors = {...phaseColors, ...wtColors};

const nodes = Array.from(nodeSet).map(name => {
  let color = null;
  if (name.includes('(unallocated)')) color = '#F2495C';
  else if (name.includes('(untagged')) color = '#808080';
  else if (name.includes('(other)')) color = '#C0C0C0';
  else {
    const parts = name.split(': ');
    const val = parts.length > 1 ? parts.slice(1).join(': ') : name;
    if (allColors[val]) color = allColors[val];
  }
  return { name, itemStyle: color ? { color } : {} };
});

return {
  tooltip: {
    trigger: 'item',
    formatter: p => {
      const strip = s => { const ci = s.indexOf(': '); return ci >= 0 ? s.slice(ci + 2) : s; };
      if (p.dataType === 'edge')
        return strip(p.data.source) + ' \u2192 ' + strip(p.data.target) + '<br/>$' + p.data.value.toFixed(2);
      return strip(p.name) + '<br/>$' + ((p.value || 0).toFixed(2));
    }
  },
  series: [{
    type: 'sankey',
    layout: 'none',
    emphasis: { focus: 'adjacency' },
    nodeAlign: 'left',
    data: nodes,
    links: links,
    lineStyle: { color: 'gradient', opacity: 0.4 },
    label: {
      show: true, position: 'right', fontSize: 11,
      formatter: p => { let lbl = p.name; const ci = lbl.indexOf(': '); if (ci >= 0) lbl = lbl.slice(ci + 2); if (lbl.length > 20) lbl = lbl.slice(0,18)+'…'; return lbl + '\n$' + ((p.value || 0).toFixed(0)); }
    },
    nodeGap: 12,
    nodeWidth: 20
  }]
};
